825	static common_chat_params common_chat_params_init_ministral_3(const common_chat_template &    tmpl,
826	                                                              const autoparser::generation_params & inputs) {
827	    common_chat_params data;
828	
829	    // Build up messages to follow the format: https://huggingface.co/mistralai/Ministral-3-14B-Reasoning-2512/blob/main/chat_template.jinja
830	    auto adjusted_messages = json::array();
831	    for (const auto & msg : inputs.messages) {
832	        auto role = msg.value("role", "");
833	        if (role != "system" && role != "assistant") {
834	            // Only adjust system and assistant messages. Interestingly, the system message may contain thinking.
835	            adjusted_messages.push_back(msg);
836	            continue;
837	        }
838	
839	        auto content = json::array();
840	
841	        // If message contains `reasoning_content`, add it as a block of type `thinking`
842	        if (msg.contains("reasoning_content") && msg.at("reasoning_content").is_string()) {
843	            content.push_back({
844	                { "type",     "thinking"                                     },
845	                { "thinking", msg.at("reasoning_content").get<std::string>() },
846	            });
847	        }
848	
849	        // If message contains `content`, add it as a block of type `text`
850	        if (msg.contains("content")) {
851	            if (msg.at("content").is_string()) {
852	                content.push_back({
853	                    { "type", "text"                               },
854	                    { "text", msg.at("content").get<std::string>() },
855	                });
856	            } else if (msg.at("content").is_array()) {
857	                auto blocks = msg.at("content");
858	                content.insert(content.end(), blocks.begin(), blocks.end());
859	            }
860	        }
861	
862	        auto adjusted       = msg;
863	        adjusted["content"] = content;
864	        adjusted.erase("reasoning_content");
865	        adjusted_messages.push_back(adjusted);
866	    }
867	
868	    auto has_tools         = inputs.tools.is_array() && !inputs.tools.empty();
869	    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
870	    auto include_grammar   = true;
871	
872	    data.supports_thinking  = true;
873	    data.thinking_start_tag = "[THINK]";
874	    data.thinking_end_tag   = "[/THINK]";
875	    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs, /* messages_override = */ adjusted_messages);
876	    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
877	    data.preserved_tokens  = {
878	        "[THINK]",
879	        "[/THINK]",
880	        "[TOOL_CALLS]",
881	        "[ARGS]",
882	    };
883	
884	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
885	        auto generation_prompt = p.prefix(inputs.generation_prompt, "[THINK]");
886	        auto reasoning =
887	            extract_reasoning ? p.optional("[THINK]" + p.reasoning(p.until("[/THINK]")) + "[/THINK]") : p.eps();
888	
889	        // Response format parser
890	        if (inputs.json_schema.is_object() && !inputs.json_schema.empty()) {
891	            // Ministral wants to emit json surrounded by code fences
892	            return generation_prompt + (reasoning << "```json" << p.content(p.schema(p.json(), "response-format", inputs.json_schema)) << "```");
893	        }
894	
895	        // Tool call parser
896	        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
897	            auto tool_choice = p.choice();
898	            foreach_function(inputs.tools, [&](const json & tool) {
899	                const auto & function = tool.at("function");
900	                std::string  name     = function.at("name");
901	                const auto & schema   = function.at("parameters");
902	
903	                tool_choice |=
904	                    p.rule("tool-" + name, p.tool_open(p.tool_name(p.literal(name)) + "[ARGS]") +
905	                                               p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", schema)));
906	            });
907	
908	            auto min_calls  = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED ? 1 : 0;
909	            auto max_calls  = inputs.parallel_tool_calls ? -1 : 1;
910	            auto tool_calls = p.trigger_rule("tool-call", p.repeat("[TOOL_CALLS]" + tool_choice, min_calls, max_calls));
911	
912	            return generation_prompt + (reasoning << p.content(p.until("[TOOL_CALLS]")) << tool_calls);
913	        }
914	
915	        // Content only parser
916	        include_grammar = false;
917	        return generation_prompt + (reasoning << p.content(p.rest()));
918	    });
919	
920	    data.parser = parser.save();
921	
922	    if (include_grammar) {
923	        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
924	
925	        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
926	            foreach_function(inputs.tools, [&](const json & tool) {
927	                const auto & function = tool.at("function");
928	                auto         schema   = function.at("parameters");
929	                builder.resolve_refs(schema);
930	            });
931	            parser.build_grammar(builder, data.grammar_lazy);
932	        });
933	
934	        data.grammar_triggers = {
935	            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
936	        };
937	    }
938	
939	    return data;
940	}
